"""
Parameterized generator for GH908_pymc_8174.

Source PR:    https://github.com/pymc-devs/pymc/pull/8174
Source Issue: https://github.com/pymc-devs/pymc/issues/8173

Seed varies: renames 'allowed' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH908_pymc_8174'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH908_pymc_8174'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('allowed', 'allowed' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH908_pymc_8174',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pymc-devs/pymc',
                "pr_number": 8174,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pymc-devs/pymc/pull/8174",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'pymc/logprob/transform_value.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport warnings\n\nfrom collections.abc import Sequence\n\nimport numpy as np\n\nfrom pytensor.graph import Apply, Op\nfrom pytensor.graph.features import AlreadyThere, Feature\nfrom pytensor.graph.fg import FunctionGraph\nfrom pytensor.graph.rewriting.basic import GraphRewriter, in2out, node_rewriter\nfrom pytensor.tensor.variable import TensorVariable\n\nfrom pymc.logprob.abstract import MeasurableOp, ValuedRV, _logprob, valued_rv\nfrom pymc.logprob.rewriting import cleanup_ir_rewrites_db\nfrom pymc.logprob.transforms import Transform\nfrom pymc.logprob.utils import get_related_valued_nodes\n\n\nclass TransformedValue(Op):\n    """A no-op that pairs the original value with its transformed version.\n\n    This is introduced by the `TransformValuesRewrite`\n    """\n\n    view_map = {0: [0]}\n\n    def make_node(self, tran_value: TensorVariable, value: TensorVariable):\n        return Apply(self, [tran_value, value], [tran_value.type()])\n\n    def perform(self, node, inputs, outputs):\n        warnings.warn("TransformedValue should not be present in the final graph!")\n        outputs[0][0] = inputs[0]\n\n    def infer_shape(self, fgraph, node, input_shapes):\n        return [input_shapes[0]]\n\n\ntransformed_value = TransformedValue()\n\n\nclass TransformedValueRV(MeasurableOp, Op):\n    """A no-op that identifies RVs whose values were transformed.\n\n    This is introduced by the `TransformValuesRewrite`\n    """\n\n    __props__ = ("transforms",)\n\n    def __init__(self, transforms: Sequence[Transform]):\n        self.transforms = tuple(transforms)\n        super().__init__()\n\n    def make_node(self, *rv_outputs):\n        return Apply(self, rv_outputs, [out.type() for out in rv_outputs])\n\n    def perform(self, node, inputs, outputs):\n        raise NotImplementedError(\n            "`TransformedRV` `Op`s should be removed from graphs used for computation."\n        )\n\n    def infer_shape(self, fgraph, node, input_shapes):\n        return input_shapes\n\n\n@_logprob.register(TransformedValueRV)\ndef transformed_value_logprob(op, values, *rv_outs, use_jacobian=True, **kwargs):\n    """Compute the log-probability graph for a `TransformedRV`.\n\n    This is introduced by the `TransformValuesRewrite`\n    """\n    rv_op = rv_outs[0].owner.op\n    rv_inputs = rv_outs[0].owner.inputs\n    logprobs = _logprob(rv_op, values, *rv_inputs, **kwargs)\n\n    if not isinstance(logprobs, Sequence):\n        logprobs = [logprobs]\n\n    # Handle jacobian\n    assert len(values) == len(logprobs) == len(op.transforms)\n    logprobs_jac = []\n    for value, transform, logp in zip(values, op.transforms, logprobs):\n        if transform is None:\n            logprobs_jac.append(logp)\n            continue\n\n        assert isinstance(value.owner.op, TransformedValue)\n        original_forward_value = value.owner.inputs[1]\n        log_jac_det = transform.log_jac_det(original_forward_value, *rv_inputs).copy()\n        # The jacobian determinant has less dims than the logp\n        # when a multivariate transform (like Simplex or Ordered) is applied to univariate distributions.\n        # In this case we have to reduce the last logp dimensions, as they are no longer independent\n        if log_jac_det.ndim < logp.ndim:\n            diff_ndims = logp.ndim - log_jac_det.ndim\n            logp = logp.sum(axis=np.arange(-diff_ndims, 0))\n        # This case is sometimes, but not always, trivial to accomodate depending on the "space rank" of the\n        # multivariate distribution. See https://proceedings.mlr.press/v130/radul21a.html\n        elif log_jac_det.ndim > logp.ndim:\n            raise NotImplementedError(\n                f"Univariate transform {transform} cannot be applied to multivariate {rv_op}"\n            )\n        # Check there is no broadcasting between logp and jacobian\n        if logp.type.broadcastable != log_jac_det.type.broadcastable:\n            raise ValueError(\n                f"The logp of {rv_op} and log_jac_det of {transform} are not allowed to broadcast together. "\n                "There is a bug in the implementation of either one."\n            )\n\n        if use_jacobian:\n            if value.name:\n                log_jac_det.name = f"{value.name}_jacobian"\n            logprobs_jac.append(logp + log_jac_det)\n        else:\n            # We still want to use the reduced logp, even though the jacobian isn\'t included\n            logprobs_jac.append(logp)\n\n    return logprobs_jac\n\n\n@node_rewriter(tracks=[ValuedRV])\ndef transform_values(fgraph: FunctionGraph, node: Apply) -> list[Apply] | None:\n    """Apply transforms to value variables.\n\n    It is assumed that the input value variables correspond to forward\n    transformations, usually chosen in such a way that the values are\n    unconstrained on the real line.\n\n    For example, if ``Y = halfnormal(...)``, we assume the respective value\n    variable is specified on the log scale and back-transform it to obtain\n    ``Y`` on the natural scale.\n    """\n    values_to_transforms: TransformValuesMapping | None = getattr(\n        fgraph, "values_to_transforms", None\n    )\n\n    if values_to_transforms is None:\n        return None\n\n    rv_node = node.inputs[0].owner\n    valued_nodes = get_related_valued_nodes(fgraph, rv_node)\n    rvs = [valued_var.inputs[0] for valued_var in valued_nodes]\n    values = [valued_var.inputs[1] for valued_var in valued_nodes]\n    transforms = [values_to_transforms.get(value, None) for value in values]\n\n    if all(transform is None for transform in transforms):\n        return None\n\n    transformed_rv_op = TransformedValueRV(transforms)\n    transformed_rv_node = transformed_rv_op.make_node(*rvs)\n\n    # We now assume that the old value variable represents the *transformed space*.\n    # This means that we need to replace all instance of the old value variable\n    # with "inversely/un-" transformed versions of itself.\n    replacements = {}\n    for valued_node, transformed_rv, transform in zip(\n        valued_nodes, transformed_rv_node.outputs, transforms\n    ):\n        rv, value = valued_node.inputs\n        [val_rv] = valued_node.outputs\n\n        if transform is None:\n            transformed_val = value\n\n        else:\n            transformed_val = transformed_value(\n                transform.backward(value, *rv.owner.inputs),\n                value,\n            )\n\n            value_name = value.name\n            transform_name = getattr(transform, "name", None)\n            if value_name and transform_name:\n                transformed_val.name = f"{value_name}_{transform.name}"\n\n        replacements[val_rv] = valued_rv(transformed_rv, transformed_val)\n\n    return replacements\n\n\nclass TransformValuesMapping(Feature):\n    r"""A `Feature` that maintains a map between value variables and their transforms."""\n\n    def __init__(self, values_to_transforms):\n        self.values_to_transforms = values_to_transforms.copy()\n\n    def on_attach(self, fgraph):\n        if hasattr(fgraph, "values_to_transforms"):\n            raise AlreadyThere()\n\n        fgraph.values_to_transforms = self.values_to_transforms\n\n\nclass TransformValuesRewrite(GraphRewriter):\n    r"""Transforms value variables according to a map."""\n\n    transform_rewrite = in2out(transform_values, ignore_newtrees=True)\n\n    def __init__(\n        self,\n        values_to_transforms: dict[TensorVariable, Transform | None],\n    ):\n        """Create the rewriter.\n\n        Parameters\n        ----------\n        values_to_transforms\n            Mapping between value variables and their transformations.  Each\n            value variable can be assigned one of `RVTransform`, or ``None``.\n            If a transform is not specified for a specific value variable it will\n            not be transformed.\n\n        """\n        self.values_to_transforms = values_to_transforms\n\n    def add_requirements(self, fgraph):\n        values_transforms_feature = TransformValuesMapping(self.values_to_transforms)\n        fgraph.attach_feature(values_transforms_feature)\n\n    def apply(self, fgraph: FunctionGraph):\n        self.transform_rewrite.rewrite(fgraph)\n\n\n@node_rewriter([TransformedValue])\ndef remove_TransformedValues(fgraph, node):\n    return [node.inputs[0]]\n\n\n@node_rewriter([TransformedValueRV])\ndef remove_TransformedValueRVs(fgraph, node):\n    return node.inputs\n\n\ncleanup_ir_rewrites_db.register(\n    "remove_TransformedValues",\n    remove_TransformedValues,\n    "cleanup",\n    "transform",\n)\n\n\ncleanup_ir_rewrites_db.register(\n    "remove_TransformedValueRVs",\n    remove_TransformedValueRVs,\n    "cleanup",\n    "transform",\n)\n',
            'tests/distributions/test_transform.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\n\nimport numpy as np\nimport pytensor\nimport pytensor.tensor as pt\nimport pytest\n\nfrom numpy.testing import assert_allclose, assert_array_equal\nfrom pytensor.tensor.variable import TensorConstant\n\nimport pymc as pm\nimport pymc.distributions.transforms as tr\n\nfrom pymc.logprob.basic import transformed_conditional_logp\nfrom pymc.logprob.transforms import Transform\nfrom pymc.pytensorf import floatX, jacobian\nfrom pymc.testing import (\n    Circ,\n    MultiSimplex,\n    R,\n    Rminusbig,\n    Rplusbig,\n    Simplex,\n    SortedVector,\n    Unit,\n    UnitSortedVector,\n    Vector,\n)\n\n# some transforms (stick breaking) require addition of small slack in order to be numerically\n# stable. The minimal addable slack for float32 is higher thus we need to be less strict\ntol = 1e-7 if pytensor.config.floatX == "float64" else 1e-5\n\n\ndef check_transform(transform, domain, constructor=pt.scalar, test=0, rv_var=None):\n    x = constructor("x")\n    x.tag.test_value = test\n    if rv_var is None:\n        rv_var = x\n    rv_inputs = rv_var.owner.inputs if rv_var.owner else []\n    # test forward and forward_val\n    # FIXME: What\'s being tested here?  That the transformed graph can compile?\n    forward_f = pytensor.function([x], transform.forward(x, *rv_inputs))\n    # test transform identity\n    z = transform.backward(transform.forward(x, *rv_inputs))\n    assert z.type == x.type\n    identity_f = pytensor.function([x], z, *rv_inputs)\n    for val in domain.vals:\n        assert_allclose(val, identity_f(val), atol=tol)\n\n\ndef check_vector_transform(transform, domain, rv_var=None):\n    return check_transform(\n        transform, domain, pt.vector, test=floatX(np.array([0, 0])), rv_var=rv_var\n    )\n\n\ndef get_values(transform, domain=R, constructor=pt.scalar, test=0, rv_var=None):\n    x = constructor("x")\n    x.tag.test_value = test\n    if rv_var is None:\n        rv_var = x\n    rv_inputs = rv_var.owner.inputs if rv_var.owner else []\n    f = pytensor.function([x], transform.backward(x, *rv_inputs))\n    return np.array([f(val) for val in domain.vals])\n\n\ndef check_jacobian_det(\n    transform,\n    domain,\n    constructor=pt.scalar,\n    test=0,\n    make_comparable=None,\n    elemwise=False,\n    rv_var=None,\n):\n    y = constructor("y")\n    y.tag.test_value = test\n\n    if rv_var is None:\n        rv_var = y\n\n    rv_inputs = rv_var.owner.inputs if rv_var.owner else []\n\n    x = transform.backward(y, *rv_inputs)\n    # Assume non-injective transforms are symmetric around the origin\n    if isinstance(x, tuple):\n        x = x[-1]\n    if make_comparable:\n        x = make_comparable(x)\n\n    if not elemwise:\n        jac = pt.log(pt.abs(pt.linalg.det(jacobian(x, [y]))))\n    else:\n        jac = pt.log(pt.abs(pt.diag(jacobian(x, [y]))))\n\n    # ljd = log jacobian det\n    actual_ljd = pytensor.function([y], jac)\n\n    computed_ljd = pytensor.function(\n        [y], pt.as_tensor_variable(transform.log_jac_det(y, *rv_inputs)), on_unused_input="ignore"\n    )\n\n    for yval in domain.vals:\n        assert_allclose(actual_ljd(yval), computed_ljd(yval), rtol=tol, atol=tol)\n\n\ndef test_simplex():\n    check_vector_transform(tr.simplex, Simplex(2))\n    check_vector_transform(tr.simplex, Simplex(4))\n\n    check_transform(\n        tr.simplex, MultiSimplex(3, 2), constructor=pt.matrix, test=floatX(np.zeros((2, 2)))\n    )\n\n\ndef test_simplex_bounds():\n    vals = get_values(tr.simplex, Vector(R, 2), pt.vector, floatX(np.array([0, 0])))\n\n    assert_allclose(vals.sum(axis=1), 1, tol)\n    assert_array_equal(vals > 0, True)\n    assert_array_equal(vals < 1, True)\n\n    check_jacobian_det(\n        tr.simplex, Vector(R, 2), pt.vector, floatX(np.array([0, 0])), lambda x: x[:-1]\n    )\n\n\ndef test_simplex_accuracy():\n    val = floatX(np.array([-30]))\n    x = pt.vector("x")\n    x.tag.test_value = val\n    identity_f = pytensor.function([x], tr.simplex.forward(tr.simplex.backward(x)))\n    assert_allclose(val, identity_f(val), tol)\n\n\ndef test_sum_to_1():\n    check_vector_transform(tr.sum_to_1, Simplex(2))\n    check_vector_transform(tr.sum_to_1, Simplex(4))\n\n    check_jacobian_det(\n        tr.sum_to_1,\n        Vector(Unit, 2),\n        pt.vector,\n        floatX(np.array([0, 0])),\n        lambda x: x[:-1],\n    )\n\n\ndef test_log():\n    check_transform(tr.log, Rplusbig)\n\n    check_jacobian_det(tr.log, Rplusbig, elemwise=True)\n    check_jacobian_det(tr.log, Vector(Rplusbig, 2), pt.vector, [0, 0], elemwise=True)\n\n    vals = get_values(tr.log)\n    assert_array_equal(vals > 0, True)\n\n\n@pytest.mark.skipif(\n    pytensor.config.floatX == "float32", reason="Test is designed for 64bit precision"\n)\ndef test_log_exp_m1():\n    check_transform(tr.log_exp_m1, Rplusbig)\n\n    check_jacobian_det(tr.log_exp_m1, Rplusbig, elemwise=True)\n    check_jacobian_det(tr.log_exp_m1, Vector(Rplusbig, 2), pt.vector, [0, 0], elemwise=True)\n\n    vals = get_values(tr.log_exp_m1)\n    assert_array_equal(vals > 0, True)\n\n\ndef test_logodds():\n    check_transform(tr.logodds, Unit)\n\n    check_jacobian_det(tr.logodds, Unit, elemwise=True)\n    check_jacobian_det(tr.logodds, Vector(Unit, 2), pt.vector, [0.5, 0.5], elemwise=True)\n\n    vals = get_values(tr.logodds)\n    assert_array_equal(vals > 0, True)\n    assert_array_equal(vals < 1, True)\n\n\ndef test_lowerbound():\n    trans = tr.Interval(0.0, None)\n    check_transform(trans, Rplusbig)\n\n    check_jacobian_det(trans, Rplusbig, elemwise=True)\n    check_jacobian_det(trans, Vector(Rplusbig, 2), pt.vector, [0, 0], elemwise=True)\n\n    vals = get_values(trans)\n    assert_array_equal(vals > 0, True)\n\n\ndef test_upperbound():\n    trans = tr.Interval(None, 0.0)\n    check_transform(trans, Rminusbig)\n\n    check_jacobian_det(trans, Rminusbig, elemwise=True)\n    check_jacobian_det(trans, Vector(Rminusbig, 2), pt.vector, [-1, -1], elemwise=True)\n\n    vals = get_values(trans)\n    assert_array_equal(vals < 0, True)\n\n\ndef test_interval():\n    for a, b in [(-4, 5.5), (0.1, 0.7), (-10, 4.3)]:\n        domain = Unit * np.float64(b - a) + np.float64(a)\n\n        trans = tr.Interval(a, b)\n        check_transform(trans, domain)\n\n        check_jacobian_det(trans, domain, elemwise=True)\n\n        vals = get_values(trans)\n        assert_array_equal(vals > a, True)\n        assert_array_equal(vals < b, True)\n\n\n@pytest.mark.skipif(\n    pytensor.config.floatX == "float32", reason="Test is designed for 64bit precision"\n)\ndef test_interval_near_boundary():\n    lb = -1.0\n    ub = 1e-7\n    x0 = np.nextafter(ub, lb)\n\n    with pm.Model() as model:\n        pm.Uniform("x", initval=x0, lower=lb, upper=ub)\n\n    with pytensor.config.change_flags(numba__fastmath=False):\n        log_prob = model.point_logps()\n    assert_allclose(list(log_prob.values()), floatX(np.array([-52.68])))\n\n\ndef test_circular():\n    trans = tr.circular\n    check_transform(trans, Circ)\n\n    check_jacobian_det(trans, Circ)\n\n    vals = get_values(trans)\n    assert_array_equal(vals > -np.pi, True)\n    assert_array_equal(vals < np.pi, True)\n\n    assert isinstance(trans.forward(1, None), TensorConstant)\n\n\ndef test_ordered():\n    check_vector_transform(tr.ordered, SortedVector(6))\n\n    check_jacobian_det(\n        tr.ordered, Vector(R, 2), pt.vector, floatX(np.array([0, 0])), elemwise=False\n    )\n\n    vals = get_values(tr.ordered, Vector(R, 3), pt.vector, floatX(np.zeros(3)))\n    assert_array_equal(np.diff(vals) >= 0, True)\n\n    # Check that positive=True creates positive and still ordered values\n    vals = get_values(tr.Ordered(positive=True), Vector(R, 3), pt.vector, floatX(np.zeros(3)))\n    assert_array_equal(vals > 0, True)\n    assert_array_equal(np.diff(vals) >= 0, True)\n\n    # Check that positive=True and ascending=False creates descending values\n    vals = get_values(\n        tr.Ordered(positive=True, ascending=False), Vector(R, 3), pt.vector, floatX(np.zeros(3))\n    )\n    assert_array_equal(vals > 0, True)\n    assert_array_equal(np.diff(vals) <= 0, True)\n\n    # Check that forward and backward are still inverses\n    ord, vals = tr.Ordered(positive=True, ascending=False), np.array([0.3, 0.2, 0.1])\n    assert_allclose(vals, ord.backward(ord.forward(vals)).eval())\n\n    # Check the jacobian for positive=True and ascending=False\n    check_jacobian_det(\n        tr.Ordered(positive=True, ascending=False),\n        Vector(R, 2),\n        pt.vector,\n        floatX(np.array([1, 1])),\n        elemwise=False,\n    )\n\n\ndef test_chain_values():\n    chain_tranf = tr.Chain([tr.logodds, tr.ordered])\n    vals = get_values(chain_tranf, Vector(R, 5), pt.vector, floatX(np.zeros(5)))\n    assert_array_equal(np.diff(vals) >= 0, True)\n\n\ndef test_chain_vector_transform():\n    chain_tranf = tr.Chain([tr.logodds, tr.ordered])\n    check_vector_transform(chain_tranf, UnitSortedVector(3))\n\n\n@pytest.mark.xfail(reason="Fails due to precision issue. Values just close to expected.")\ndef test_chain_jacob_det():\n    chain_tranf = tr.Chain([tr.logodds, tr.ordered])\n    check_jacobian_det(chain_tranf, Vector(R, 4), pt.vector, floatX(np.zeros(4)), elemwise=False)\n\n\nclass TestElementWiseLogp:\n    def build_model(self, distfam, params, size, transform, initval=None):\n        if initval is not None:\n            initval = pm.floatX(initval)\n        with pm.Model() as m:\n            distfam("x", size=size, transform=transform, initval=initval, **params)\n        return m\n\n    def check_transform_elementwise_logp(self, model, vector_transform=False):\n        x = model.free_RVs[0]\n        x_val_transf = model.rvs_to_values[x]\n        transform = model.rvs_to_transforms[x]\n        x_val_untransf = transform.backward(x_val_transf, *x.owner.inputs)\n\n        point = model.initial_point(0)\n        test_array_transf = floatX(np.random.randn(*point[x_val_transf.name].shape))\n        test_array_untransf = x_val_untransf.eval({x_val_transf: test_array_transf})\n        log_jac_det = transform.log_jac_det(x_val_transf, *x.owner.inputs)\n\n        [transform_logp] = transformed_conditional_logp(\n            (x,),\n            rvs_to_values={x: x_val_transf},\n            rvs_to_transforms={x: transform},\n        )\n        [untransform_logp] = transformed_conditional_logp(\n            (x,),\n            rvs_to_values={x: x_val_untransf},\n            rvs_to_transforms={},\n        )\n        if vector_transform:\n            assert transform_logp.ndim == (x.ndim - 1) == log_jac_det.ndim\n        else:\n            assert transform_logp.ndim == x.ndim == log_jac_det.ndim\n\n        transform_logp_eval = transform_logp.eval({x_val_transf: test_array_transf})\n        untransform_logp_eval = untransform_logp.eval({x_val_untransf: test_array_untransf})\n        log_jac_det_eval = log_jac_det.eval({x_val_transf: test_array_transf})\n        # Summing the log_jac_det separately from the untransform_logp ensures there is no broadcasting between terms\n        assert_allclose(\n            transform_logp_eval.sum(),\n            untransform_logp_eval.sum() + log_jac_det_eval.sum(),\n            rtol=tol,\n        )\n\n    def check_vectortransform_elementwise_logp(self, model):\n        self.check_transform_elementwise_logp(model, vector_transform=True)\n\n    @pytest.mark.parametrize(\n        "sigma,size",\n        [\n            (2.5, 2),\n            (5.0, (2, 3)),\n            (np.ones(3) * 10.0, (4, 3)),\n        ],\n    )\n    def test_half_normal(self, sigma, size):\n        model = self.build_model(pm.HalfNormal, {"sigma": sigma}, size=size, transform=tr.log)\n        self.check_transform_elementwise_logp(model)\n\n    @pytest.mark.parametrize("lam,size", [(2.5, 2), (5.0, (2, 3)), (np.ones(3), (4, 3))])\n    def test_exponential(self, lam, size):\n        model = self.build_model(pm.Exponential, {"lam": lam}, size=size, transform=tr.log)\n        self.check_transform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "a,b,size",\n        [\n            (1.0, 1.0, 2),\n            (0.5, 0.5, (2, 3)),\n            (np.ones(3), np.ones(3), (4, 3)),\n        ],\n    )\n    def test_beta(self, a, b, size):\n        model = self.build_model(pm.Beta, {"alpha": a, "beta": b}, size=size, transform=tr.logodds)\n        self.check_transform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "lower,upper,size",\n        [\n            (0.0, 1.0, 2),\n            (0.5, 5.5, (2, 3)),\n            (pm.floatX(np.zeros(3)), pm.floatX(np.ones(3)), (4, 3)),\n        ],\n    )\n    def test_uniform(self, lower, upper, size):\n        def transform_params(*inputs):\n            _, _, lower, upper = inputs\n            lower = pt.as_tensor_variable(lower) if lower is not None else None\n            upper = pt.as_tensor_variable(upper) if upper is not None else None\n            return lower, upper\n\n        interval = tr.Interval(bounds_fn=transform_params)\n        model = self.build_model(\n            pm.Uniform, {"lower": lower, "upper": upper}, size=size, transform=interval\n        )\n        self.check_transform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "lower, c, upper, size",\n        [\n            (0.0, 1.0, 2.0, 2),\n            (-10, 0, 200, (2, 3)),\n            (floatX(np.zeros(3)), floatX(np.ones(3)), floatX(np.ones(3)), (4, 3)),\n        ],\n    )\n    def test_triangular(self, lower, c, upper, size):\n        def transform_params(*inputs):\n            _, _, lower, _, upper = inputs\n            lower = pt.as_tensor_variable(lower) if lower is not None else None\n            upper = pt.as_tensor_variable(upper) if upper is not None else None\n            return lower, upper\n\n        interval = tr.Interval(bounds_fn=transform_params)\n        model = self.build_model(\n            pm.Triangular, {"lower": lower, "c": c, "upper": upper}, size=size, transform=interval\n        )\n        self.check_transform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "mu,kappa,size",\n        [(0.0, 1.0, 2), (-0.5, 5.5, (2, 3)), (floatX(np.zeros(3)), floatX(np.ones(3)), (4, 3))],\n    )\n    def test_vonmises(self, mu, kappa, size):\n        model = self.build_model(\n            pm.VonMises, {"mu": mu, "kappa": kappa}, size=size, transform=tr.circular\n        )\n        self.check_transform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "a,size", [(np.ones(2), None), (np.ones((2, 3)) * 0.5, None), (np.ones(3), (4,))]\n    )\n    def test_dirichlet(self, a, size):\n        model = self.build_model(pm.Dirichlet, {"a": a}, size=size, transform=tr.simplex)\n        self.check_vectortransform_elementwise_logp(model)\n\n    def test_normal_ordered(self):\n        model = self.build_model(\n            pm.Normal,\n            {"mu": 0.0, "sigma": 1.0},\n            size=3,\n            initval=np.asarray([-1.0, 1.0, 4.0]),\n            transform=tr.ordered,\n        )\n        self.check_vectortransform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "sigma,size",\n        [\n            (2.5, (2,)),\n            (np.ones(3), (4, 3)),\n        ],\n    )\n    def test_half_normal_ordered(self, sigma, size):\n        initval = np.sort(np.abs(np.random.randn(*size)))\n        model = self.build_model(\n            pm.HalfNormal,\n            {"sigma": sigma},\n            size=size,\n            initval=initval,\n            transform=tr.Chain([tr.log, tr.ordered]),\n        )\n        self.check_vectortransform_elementwise_logp(model)\n\n    @pytest.mark.parametrize("lam,size", [(2.5, (2,)), (np.ones(3), (4, 3))])\n    def test_exponential_ordered(self, lam, size):\n        initval = np.sort(np.abs(np.random.randn(*size)))\n        model = self.build_model(\n            pm.Exponential,\n            {"lam": lam},\n            size=size,\n            initval=initval,\n            transform=tr.Chain([tr.log, tr.ordered]),\n        )\n        self.check_vectortransform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "a,b,size",\n        [\n            (\n                1.0,\n                1.0,\n                (2,),\n            ),\n            (np.ones(3), np.ones(3), (4, 3)),\n        ],\n    )\n    def test_beta_ordered(self, a, b, size):\n        initval = np.sort(np.abs(np.random.rand(*size)))\n        model = self.build_model(\n            pm.Beta,\n            {"alpha": a, "beta": b},\n            size=size,\n            initval=initval,\n            transform=tr.Chain([tr.logodds, tr.ordered]),\n        )\n        self.check_vectortransform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "lower,upper,size",\n        [(0.0, 1.0, (2,)), (pm.floatX(np.zeros(3)), pm.floatX(np.ones(3)), (4, 3))],\n    )\n    def test_uniform_ordered(self, lower, upper, size):\n        def transform_params(*inputs):\n            _, _, lower, upper = inputs\n            lower = pt.as_tensor_variable(lower) if lower is not None else None\n            upper = pt.as_tensor_variable(upper) if upper is not None else None\n            return lower, upper\n\n        interval = tr.Interval(bounds_fn=transform_params)\n\n        initval = np.sort(np.abs(np.random.rand(*size)))\n        model = self.build_model(\n            pm.Uniform,\n            {"lower": lower, "upper": upper},\n            size=size,\n            initval=initval,\n            transform=tr.Chain([interval, tr.ordered]),\n        )\n        self.check_vectortransform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "mu,kappa,size", [(0.0, 1.0, (2,)), (floatX(np.zeros(3)), floatX(np.ones(3)), (4, 3))]\n    )\n    def test_vonmises_ordered(self, mu, kappa, size):\n        initval = np.sort(np.abs(np.random.rand(*size)))\n        model = self.build_model(\n            pm.VonMises,\n            {"mu": mu, "kappa": kappa},\n            size=size,\n            initval=initval,\n            transform=tr.Chain([tr.circular, tr.ordered]),\n        )\n        self.check_vectortransform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "lower,upper,size,transform",\n        [\n            (0.0, 1.0, (2,), tr.simplex),\n            (0.5, 5.5, (2, 3), tr.simplex),\n            (\n                floatX(np.zeros(3)),\n                floatX(np.ones(3)),\n                (4, 3),\n                tr.Chain([tr.sum_to_1, tr.logodds]),\n            ),\n        ],\n    )\n    def test_uniform_other(self, lower, upper, size, transform):\n        initval = np.ones(size) / size[-1]\n        model = self.build_model(\n            pm.Uniform,\n            {"lower": lower, "upper": upper},\n            size=size,\n            initval=initval,\n            transform=transform,\n        )\n        self.check_vectortransform_elementwise_logp(model)\n\n    @pytest.mark.parametrize(\n        "mu,cov,size,shape",\n        [\n            (floatX(np.zeros(2)), floatX(np.diag(np.ones(2))), None, (2,)),\n            (floatX(np.zeros(3)), floatX(np.diag(np.ones(3))), (4,), (4, 3)),\n        ],\n    )\n    @pytest.mark.parametrize("transform", (tr.ordered, tr.sum_to_1))\n    def test_mvnormal_transform(self, mu, cov, size, shape, transform):\n        initval = np.sort(np.random.randn(*shape))\n        model = self.build_model(\n            pm.MvNormal,\n            {"mu": mu, "cov": cov},\n            size=size,\n            initval=initval,\n            transform=transform,\n        )\n        self.check_vectortransform_elementwise_logp(model)\n\n\ndef test_triangular_transform():\n    with pm.Model() as m:\n        x = pm.Triangular("x", lower=0, c=1, upper=2)\n\n    transform = m.rvs_to_transforms[x]\n    assert np.isclose(transform.backward(-np.inf, *x.owner.inputs).eval(), 0)\n    assert np.isclose(transform.backward(np.inf, *x.owner.inputs).eval(), 2)\n\n\ndef test_interval_transform_raises():\n    with pytest.raises(ValueError, match="Lower and upper interval bounds cannot both be None"):\n        tr.Interval(None, None)\n\n    with pytest.raises(ValueError, match="Interval bounds must be constant values"):\n        tr.Interval(pt.constant(5) + 1, None)\n\n    assert tr.Interval(pt.constant(5), None)\n\n\ndef test_discrete_trafo():\n    with pm.Model():\n        with pytest.raises(ValueError) as err:\n            pm.Binomial("a", n=5, p=0.5, transform="log")\n        err.match("Transformations for discrete distributions")\n\n\ndef test_transform_univariate_dist_logp_shape():\n    with pm.Model() as m:\n        pm.Uniform("x", shape=(4, 3), transform=tr.logodds)\n\n    assert m.logp(jacobian=False, sum=False)[0].type.shape == (4, 3)\n    assert m.logp(jacobian=True, sum=False)[0].type.shape == (4, 3)\n\n    with pm.Model() as m:\n        pm.Uniform("x", shape=(4, 3), transform=tr.ordered)\n\n    assert m.logp(jacobian=False, sum=False)[0].type.shape == (4,)\n    assert m.logp(jacobian=True, sum=False)[0].type.shape == (4,)\n\n\ndef test_univariate_transform_multivariate_dist_raises():\n    with pm.Model() as m:\n        pm.Dirichlet("x", [1, 1, 1], default_transform=tr.log)\n\n    for jacobian_val in (True, False):\n        with pytest.raises(\n            NotImplementedError,\n            match="Univariate transform LogTransform cannot be applied to multivariate",\n        ):\n            m.logp(jacobian=jacobian_val)\n\n\ndef test_invalid_jacobian_broadcast_raises():\n    class BuggyTransform(Transform):\n        name = "buggy"\n\n        def forward(self, value, *inputs):\n            return value\n\n        def backward(self, value, *inputs):\n            return value\n\n        def log_jac_det(self, value, *inputs):\n            return pt.zeros_like(value.sum(-1, keepdims=True))\n\n    buggy_transform = BuggyTransform()\n\n    with pm.Model() as m:\n        pm.Uniform("x", shape=(4, 3), default_transform=buggy_transform)\n\n    for jacobian_val in (True, False):\n        with pytest.raises(\n            ValueError,\n            match="are not allowed to broadcast together. There is a bug in the implementation of either one",\n        ):\n            m.logp(jacobian=jacobian_val)\n',
            'tests/logprob/test_transform_value.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport gc\nimport operator\n\nimport numpy as np\nimport pytensor\nimport pytest\nimport scipy as sp\n\nfrom numdifftools import Derivative, Jacobian\nfrom pytensor import scan\nfrom pytensor import tensor as pt\nfrom pytensor.compile.builders import OpFromGraph\nfrom pytensor.graph import FunctionGraph\nfrom pytensor.graph.basic import equal_computations\n\nimport pymc as pm\n\nfrom pymc.distributions.transforms import _default_transform, log, logodds\nfrom pymc.logprob import conditional_logp\nfrom pymc.logprob.abstract import MeasurableOp, _logprob\nfrom pymc.logprob.transform_value import TransformValuesMapping, TransformValuesRewrite\nfrom pymc.logprob.transforms import ExpTransform, LogOddsTransform, LogTransform\nfrom pymc.testing import assert_no_rvs\nfrom tests.logprob.test_transforms import DirichletScipyDist\n\n\n@pytest.fixture(scope="module")\ndef multiout_measurable_op():\n    # Create a dummy Op that just returns the two inputs\n    mu1, mu2 = pt.scalars("mu1", "mu2")\n\n    class TestOpFromGraph(MeasurableOp, OpFromGraph):\n        def do_constant_folding(self, fgraph, node):\n            False\n\n    multiout_op = TestOpFromGraph([mu1, mu2], [mu1 + 0.0, mu2 + 0.0])\n\n    @_logprob.register(TestOpFromGraph)\n    def logp_multiout(op, values, mu1, mu2):\n        value1, value2 = values\n        return value1 + mu1, value2 + mu2\n\n    return multiout_op\n\n\ndef test_TransformValuesMapping():\n    x = pt.vector()\n    fg = FunctionGraph(outputs=[x])\n\n    tvm = TransformValuesMapping({})\n    fg.attach_feature(tvm)\n\n    tvm2 = TransformValuesMapping({})\n    fg.attach_feature(tvm2)\n\n    assert fg._features[-1] is tvm\n\n\ndef test_original_values_output_dict():\n    """\n    Test that the original unconstrained value variable appears an the key of\n    the logprob factor\n    """\n    p_rv = pt.random.beta(1, 1, name="p")\n    p_vv = p_rv.clone()\n\n    tr = TransformValuesRewrite({p_vv: logodds})\n    logp_dict = conditional_logp({p_rv: p_vv}, extra_rewrites=tr)\n\n    assert p_vv in logp_dict\n\n\n@pytest.mark.parametrize(\n    "pt_dist, dist_params, sp_dist, size",\n    [\n        (pt.random.uniform, (0, 1), sp.stats.uniform, ()),\n        (\n            pt.random.pareto,\n            (1.5, 10.5),\n            lambda b, scale: sp.stats.pareto(b, scale=scale),\n            (),\n        ),\n        (\n            pt.random.triangular,\n            (1.5, 3.0, 10.5),\n            lambda lower, mode, upper: sp.stats.triang(\n                (mode - lower) / (upper - lower), loc=lower, scale=upper - lower\n            ),\n            (),\n        ),\n        (\n            pt.random.halfnormal,\n            (0, 1),\n            sp.stats.halfnorm,\n            (),\n        ),\n        pytest.param(\n            pt.random.wald,\n            (1.5, 10.5),\n            lambda mean, scale: sp.stats.invgauss(mean / scale, scale=scale),\n            (),\n            marks=pytest.mark.xfail(\n                reason="We don\'t use PyTensor\'s Wald operator",\n                raises=NotImplementedError,\n            ),\n        ),\n        (\n            pt.random.exponential,\n            (1.5,),\n            lambda mu: sp.stats.expon(scale=mu),\n            (),\n        ),\n        pytest.param(\n            pt.random.lognormal,\n            (-1.5, 10.5),\n            lambda mu, sigma: sp.stats.lognorm(s=sigma, loc=0, scale=np.exp(mu)),\n            (),\n        ),\n        (\n            pt.random.lognormal,\n            (-1.5, 1.5),\n            lambda mu, sigma: sp.stats.lognorm(s=sigma, scale=np.exp(mu)),\n            (),\n        ),\n        pytest.param(\n            pt.random.halfcauchy,\n            (1.5, 10.5),\n            lambda alpha, beta: sp.stats.halfcauchy(loc=alpha, scale=beta),\n            (),\n            marks=pytest.mark.xfail(\n                reason="We don\'t use PyTensor\'s HalfCauchy operator",\n                raises=NotImplementedError,\n            ),\n        ),\n        (\n            pt.random.gamma,\n            (1.5, 10.5),\n            lambda alpha, inv_beta: sp.stats.gamma(alpha, scale=1.0 / inv_beta),\n            (),\n        ),\n        (\n            pt.random.invgamma,\n            (1.5, 10.5),\n            lambda alpha, beta: sp.stats.invgamma(alpha, scale=beta),\n            (),\n        ),\n        (\n            pm.ChiSquared.dist,\n            (1.5,),\n            lambda df: sp.stats.chi2(df),\n            (),\n        ),\n        pytest.param(\n            pt.random.weibull,\n            (1.5,),\n            lambda c: sp.stats.weibull_min(c),\n            (),\n            marks=pytest.mark.xfail(\n                reason="We don\'t use PyTensor\'s Weibull operator",\n                raises=NotImplementedError,\n            ),\n        ),\n        (\n            pt.random.beta,\n            (1.5, 1.5),\n            lambda alpha, beta: sp.stats.beta(alpha, beta),\n            (),\n        ),\n        (\n            pt.random.vonmises,\n            (1.5, 10.5),\n            lambda mu, kappa: sp.stats.vonmises(kappa, loc=mu),\n            (),\n        ),\n        (\n            pt.random.dirichlet,\n            (np.array([0.7, 0.3]),),\n            lambda alpha: sp.stats.dirichlet(alpha),\n            (),\n        ),\n        (\n            pt.random.dirichlet,\n            (np.array([[0.7, 0.3], [0.9, 0.1]]),),\n            lambda alpha: DirichletScipyDist(alpha),\n            None,\n        ),\n        pytest.param(\n            pt.random.dirichlet,\n            (np.array([0.3, 0.7]),),\n            lambda alpha: DirichletScipyDist(alpha),\n            (3, 2),\n        ),\n    ],\n)\ndef test_default_value_transform_logprob(pt_dist, dist_params, sp_dist, size):\n    """\n    This test takes a `RandomVariable` type, plus parameters, and uses it to\n    construct a variable ``a`` that\'s used in the graph ``b =\n    pt.random.normal(a, 1.0)``.  The transformed log-probability is then\n    computed for ``b``.  We then test that the log-probability of ``a`` is\n    properly transformed, as well as any instances of ``a`` that are used\n    elsewhere in the graph (i.e. in ``b``), by comparing the graph for the\n    transformed log-probability with the SciPy-derived log-probability--using a\n    numeric approximation to the Jacobian term.\n\n    TODO: This test is rather redundant with those in tess/distributions/test_transform.py\n    """\n\n    a = pt_dist(*dist_params, size=size)\n    a.name = "a"\n    a_value_var = pt.tensor(dtype=a.dtype, shape=(None,) * a.ndim)\n    a_value_var.name = "a_value"\n\n    b = pt.random.normal(a, 1.0)\n    b.name = "b"\n    b_value_var = b.clone()\n    b_value_var.name = "b_value"\n\n    transform = _default_transform(a.owner.op, a)\n    transform_rewrite = TransformValuesRewrite({a_value_var: transform})\n    res = conditional_logp({a: a_value_var, b: b_value_var}, extra_rewrites=transform_rewrite)\n    res_combined = pt.sum([pt.sum(factor) for factor in res.values()])\n\n    test_val_rng = np.random.RandomState(3238)\n\n    logp_vals_fn = pytensor.function([a_value_var, b_value_var], res_combined)\n\n    a_forward_fn = pytensor.function([a_value_var], transform.forward(a_value_var, *a.owner.inputs))\n    a_backward_fn = pytensor.function(\n        [a_value_var], transform.backward(a_value_var, *a.owner.inputs)\n    )\n    log_jac_fn = pytensor.function(\n        [a_value_var],\n        transform.log_jac_det(a_value_var, *a.owner.inputs),\n        on_unused_input="ignore",\n    )\n\n    for i in range(10):\n        a_dist = sp_dist(*dist_params)\n        a_val = a_dist.rvs(size=size, random_state=test_val_rng).astype(a_value_var.dtype)\n        b_dist = sp.stats.norm(a_val, 1.0)\n        b_val = b_dist.rvs(random_state=test_val_rng).astype(b_value_var.dtype)\n\n        a_trans_value = a_forward_fn(a_val)\n\n        if a_val.ndim > 0:\n\n            def jacobian_estimate_novec(value):\n                dim_diff = a_val.ndim - value.ndim\n                if dim_diff > 0:\n                    # Make sure the dimensions match the expected input\n                    # dimensions for the compiled backward transform function\n                    def a_backward_fn_(x):\n                        x_ = np.expand_dims(x, axis=list(range(dim_diff)))\n                        return a_backward_fn(x_).squeeze()\n\n                else:\n                    a_backward_fn_ = a_backward_fn\n\n                jacobian_val = Jacobian(a_backward_fn_)(value)\n\n                n_missing_dims = jacobian_val.shape[0] - jacobian_val.shape[1]\n                if n_missing_dims > 0:\n                    missing_bases = np.eye(jacobian_val.shape[0])[..., -n_missing_dims:]\n                    jacobian_val = np.concatenate([jacobian_val, missing_bases], axis=-1)\n\n                return np.linalg.slogdet(jacobian_val)[-1]\n\n            jacobian_estimate = np.vectorize(jacobian_estimate_novec, signature="(n)->()")\n\n            exp_log_jac_val = jacobian_estimate(a_trans_value)\n        else:\n            jacobian_val = np.atleast_2d(Derivative(a_backward_fn, step=1e-6)(a_trans_value))\n            exp_log_jac_val = np.linalg.slogdet(jacobian_val)[-1]\n\n        log_jac_val = log_jac_fn(a_trans_value)\n        np.testing.assert_allclose(exp_log_jac_val, log_jac_val, rtol=1e-4, atol=1e-10)\n\n        exp_logprob_val = a_dist.logpdf(a_val).sum()\n        exp_logprob_val += exp_log_jac_val.sum()\n        exp_logprob_val += b_dist.logpdf(b_val).sum()\n\n        logprob_val = logp_vals_fn(a_trans_value, b_val)\n\n        np.testing.assert_allclose(exp_logprob_val, logprob_val, rtol=1e-4, atol=1e-10)\n\n\n@pytest.mark.parametrize("use_jacobian", [True, False])\ndef test_value_transform_logprob_nojac(use_jacobian):\n    X_rv = pt.random.halfnormal(0, 3, name="X")\n    x_vv = X_rv.clone()\n    x_vv.name = "x"\n\n    transform_rewrite = TransformValuesRewrite({x_vv: log})\n    tr_logp = conditional_logp(\n        {X_rv: x_vv}, extra_rewrites=transform_rewrite, use_jacobian=use_jacobian\n    )\n    tr_logp_combined = pt.sum([pt.sum(factor) for factor in tr_logp.values()])\n\n    np.testing.assert_allclose(\n        tr_logp_combined.eval({x_vv: np.log(2.5)}),\n        sp.stats.halfnorm(0, 3).logpdf(2.5) + (np.log(2.5) if use_jacobian else 0.0),\n    )\n\n\ndef test_hierarchical_value_transform():\n    """\n    This model requires rv-value replacements in the backward transformation of\n    the value var `x`\n    """\n\n    lower_rv = pt.random.uniform(0, 1, name="lower")\n    upper_rv = pt.random.uniform(9, 10, name="upper")\n    x_rv = pt.random.uniform(lower_rv, upper_rv, name="x")\n\n    lower = lower_rv.clone()\n    upper = upper_rv.clone()\n    x = x_rv.clone()\n\n    transform_rewrite = TransformValuesRewrite(\n        {\n            lower: _default_transform(lower_rv.owner.op, lower_rv),\n            upper: _default_transform(upper_rv.owner.op, upper_rv),\n            x: _default_transform(x_rv.owner.op, x_rv),\n        }\n    )\n    logp = conditional_logp(\n        {lower_rv: lower, upper_rv: upper, x_rv: x},\n        extra_rewrites=transform_rewrite,\n    )\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n\n    assert_no_rvs(logp_combined)\n    assert not np.isinf(logp_combined.eval({lower: -10, upper: 20, x: -20}))\n\n\ndef test_nondefault_value_transform():\n    loc_rv = pt.random.uniform(-10, 10, name="loc")\n    scale_rv = pt.random.uniform(-1, 1, name="scale")\n    x_rv = pt.random.normal(loc_rv, scale_rv, name="x")\n\n    loc = loc_rv.clone()\n    scale = scale_rv.clone()\n    x = x_rv.clone()\n\n    transform_rewrite = TransformValuesRewrite(\n        {\n            loc: None,\n            scale: LogOddsTransform(),\n            x: LogTransform(),\n        }\n    )\n\n    logp = conditional_logp(\n        {loc_rv: loc, scale_rv: scale, x_rv: x},\n        extra_rewrites=transform_rewrite,\n    )\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n\n    # Check numerical evaluation matches with expected transforms\n    loc_val = 0\n    scale_val_tr = -1\n    x_val_tr = -1\n\n    scale_val = sp.special.expit(scale_val_tr)\n    x_val = np.exp(x_val_tr)\n\n    exp_logp = 0\n    exp_logp += sp.stats.uniform(-10, 20).logpdf(loc_val)\n    exp_logp += sp.stats.uniform(-1, 2).logpdf(scale_val)\n    exp_logp += np.log(scale_val) + np.log1p(-scale_val)  # logodds log_jac_det\n    exp_logp += sp.stats.norm(loc_val, scale_val).logpdf(x_val)\n    exp_logp += x_val_tr  # log log_jac_det\n\n    np.testing.assert_allclose(\n        logp_combined.eval({loc: loc_val, scale: scale_val_tr, x: x_val_tr}),\n        exp_logp,\n    )\n\n\ndef test_no_value_transform_multiout_input():\n    r"""Make sure that `Op`\\s with multiple outputs are handled correctly."""\n\n    # This SVD value is necessarily `1`, but it\'s generated by an `Op` with\n    # multiple outputs and no default output.\n    sd = pt.linalg.svd(pt.eye(1))[1][0]\n    x_rv = pt.random.normal(0, sd, name="x")\n    x = x_rv.clone()\n\n    transform_rewrite = TransformValuesRewrite({x: None})\n\n    logp = conditional_logp(\n        {x_rv: x},\n        extra_rewrites=transform_rewrite,\n    )\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n\n    np.testing.assert_allclose(\n        logp_combined.eval({x: 1}),\n        sp.stats.norm(0, 1).logpdf(1),\n    )\n\n\n@pytest.mark.parametrize("transform_x", (True, False))\n@pytest.mark.parametrize("transform_y", (True, False))\ndef test_value_transform_multiout_op(transform_x, transform_y, multiout_measurable_op):\n    x, y = multiout_measurable_op(1, 2)\n    x.name = "x"\n    y.name = "y"\n    x_vv = x.clone()\n    y_vv = y.clone()\n\n    transform_rewrite = TransformValuesRewrite(\n        {\n            x_vv: LogTransform() if transform_x else None,\n            y_vv: ExpTransform() if transform_y else None,\n        }\n    )\n\n    logp = conditional_logp({x: x_vv, y: y_vv}, extra_rewrites=transform_rewrite)\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n\n    x_vv_test = np.random.normal()\n    y_vv_test = np.abs(np.random.normal())\n\n    expected_logp = 0\n    if not transform_x:\n        expected_logp += x_vv_test + 1\n    else:\n        expected_logp += np.exp(x_vv_test) + 1 + x_vv_test\n    # y logp\n    if not transform_y:\n        expected_logp += y_vv_test + 2\n    else:\n        expected_logp += np.log(y_vv_test) + 2 - np.log(y_vv_test)\n\n    np.testing.assert_allclose(\n        logp_combined.eval({x_vv: x_vv_test, y_vv: y_vv_test}), expected_logp\n    )\n\n\ndef test_transformed_rv_and_value():\n    y_rv = pt.random.halfnormal(-1, 1, name="base_rv") + 1\n    y_rv.name = "y"\n    y_vv = y_rv.clone()\n\n    transform_rewrite = TransformValuesRewrite({y_vv: LogTransform()})\n\n    logp = conditional_logp({y_rv: y_vv}, extra_rewrites=transform_rewrite)\n    logp_combined = pt.sum([pt.sum(factor) for factor in logp.values()])\n    assert_no_rvs(logp_combined)\n    logp_fn = pytensor.function([y_vv], logp_combined)\n\n    y_test_val = -5\n\n    np.testing.assert_allclose(\n        logp_fn(y_test_val),\n        sp.stats.halfnorm(0, 1).logpdf(np.exp(y_test_val)) + y_test_val,\n    )\n\n\n@pytest.mark.filterwarnings("error")\ndef test_mixture_transform():\n    """Make sure that non-`RandomVariable` `MeasurableOp` variables can be transformed.\n\n    This test is specific to `MixtureRV`, which is derived from an `OpFromGraph`.\n    """\n\n    I_rv = pt.random.bernoulli(0.5, name="I")\n    Y_1_rv = pt.random.beta(100, 1, name="Y_1")\n    Y_2_rv = pt.random.beta(1, 100, name="Y_2")\n\n    # A `MixtureRV`, which is an `OpFromGraph` subclass, will replace this\n    # `pt.stack` in the graph\n    Y_rv = pt.stack([Y_1_rv, Y_2_rv])[I_rv]\n    Y_rv.name = "Y"\n\n    i_vv = I_rv.clone()\n    i_vv.name = "i"\n    y_vv = Y_rv.clone()\n    y_vv.name = "y"\n\n    logp_no_trans = conditional_logp(\n        {Y_rv: y_vv, I_rv: i_vv},\n    )\n    logp_no_trans_comb = pt.sum([pt.sum(factor) for factor in logp_no_trans.values()])\n\n    transform_rewrite = TransformValuesRewrite({y_vv: LogTransform()})\n\n    logp_trans = conditional_logp(\n        {Y_rv: y_vv, I_rv: i_vv},\n        extra_rewrites=transform_rewrite,\n        use_jacobian=False,\n    )\n    logp_trans_combined = pt.sum([pt.sum(factor) for factor in logp_trans.values()])\n\n    # The untransformed graph should be the same as the transformed graph after\n    # replacing the `Y_rv` value variable with a transformed version of itself\n    logp_nt_fg = FunctionGraph(outputs=[logp_no_trans_comb], clone=False)\n    y_trans = pt.exp(y_vv)\n    y_trans.name = "y_log"\n    logp_nt_fg.replace(y_vv, y_trans)\n    logp_nt = logp_nt_fg.outputs[0]\n\n    assert equal_computations([logp_nt], [logp_trans_combined])\n\n\ndef test_scan_transform():\n    """Test that Scan valued variables can be transformed"""\n\n    rng, init = pt.random.beta(1, 1, name="init").owner.outputs\n    init_vv = init.clone()\n\n    def scan_step(prev_innov, prev_rng):\n        next_rng, next_innov = pt.random.beta(\n            prev_innov * 10, (1 - prev_innov) * 10, rng=prev_rng\n        ).owner.outputs\n        return next_innov, next_rng\n\n    innov, _next_rng = scan(\n        fn=scan_step,\n        outputs_info=[init, rng],\n        n_steps=4,\n        return_updates=False,\n    )\n    innov.name = "innov"\n    innov_vv = innov.clone()\n\n    tr = TransformValuesRewrite(\n        {\n            init_vv: LogOddsTransform(),\n            innov_vv: LogOddsTransform(),\n        }\n    )\n    logp = conditional_logp({init: init_vv, innov: innov_vv}, extra_rewrites=tr, use_jacobian=True)[\n        innov_vv\n    ]\n    logp_fn = pytensor.function([init_vv, innov_vv], logp, on_unused_input="ignore")\n\n    # Create an unrolled scan graph as reference\n    innov = []\n    prev_innov = init\n    for i in range(4):\n        next_innov = pt.random.beta(prev_innov * 10, (1 - prev_innov) * 10, name="innov[i]")\n        innov.append(next_innov)\n        prev_innov = next_innov\n    innov = pt.stack(innov)\n    innov.name = "innov"\n\n    tr = TransformValuesRewrite(\n        {\n            init_vv: LogOddsTransform(),\n            innov_vv: LogOddsTransform(),\n        }\n    )\n    ref_logp = conditional_logp(\n        {init: init_vv, innov: innov_vv}, extra_rewrites=tr, use_jacobian=True\n    )[innov_vv]\n    ref_logp_fn = pytensor.function([init_vv, innov_vv], ref_logp, on_unused_input="ignore")\n\n    test_point = {\n        "init": np.array(-0.5),\n        "innov": np.full((4,), -0.5),\n    }\n    np.testing.assert_allclose(logp_fn(**test_point), ref_logp_fn(**test_point))\n\n\ndef test_weakref_leak():\n    """Check that the rewrite does not have a growing memory footprint.\n\n    See #6990\n    """\n\n    def _growth(limit=10, peak_stats={}):\n        """Vendoring of objgraph.growth\n\n        Source: https://github.com/mgedmin/objgraph/blob/94b1ca61a11109547442701800292dcfc7f59fc8/objgraph.py#L253\n        """\n        gc.collect()\n        objects = gc.get_objects()\n\n        stats = {}\n        for o in objects:\n            n = type(o).__name__\n            stats[n] = stats.get(n, 0) + 1\n\n        deltas = {}\n        for name, count in stats.items():\n            old_count = peak_stats.get(name, 0)\n            if count > old_count:\n                deltas[name] = count - old_count\n                peak_stats[name] = count\n\n        deltas = sorted(deltas.items(), key=operator.itemgetter(1), reverse=True)\n\n        if limit:\n            deltas = deltas[:limit]\n\n        return [(name, stats[name], delta) for name, delta in deltas]\n\n    rvs_to_values = {pt.random.beta(1, 1, name=f"p_{i}"): pt.scalar(f"p_{i}") for i in range(30)}\n    tr = TransformValuesRewrite(dict.fromkeys(rvs_to_values.values(), logodds))\n\n    for i in range(20):\n        conditional_logp(rvs_to_values, extra_rewrites=tr)\n        res = _growth()\n        # Only start checking after warmup\n        if i > 15:\n            assert not res, "Object counts are still growing"\n',
        }
